# ============================================================================
#  Instalador del Panel Administrativo AndanDO  (Inertia + Vue 3 + TypeScript)
# ----------------------------------------------------------------------------
#  COMO USARLO:
#   1. Coloca este archivo en la RAIZ de tu proyecto Laravel (junto a "artisan").
#   2. Abrelo en VS Code.
#   3. En la terminal integrada (PowerShell) ejecuta:
#         powershell -ExecutionPolicy Bypass -File .\setup-andando-admin.ps1
#      (o boton derecho sobre el archivo > "Ejecutar con PowerShell")
#
#  El script crea los archivos, parchea bootstrap/app.php, agrega las rutas a
#  routes/web.php y corre composer + npm. Hace backup de los archivos que toca.
# ============================================================================

$ErrorActionPreference = "Stop"
Write-Host ""
Write-Host "== Instalador Panel AndanDO ==" -ForegroundColor Cyan
Write-Host ""

# --- 0. Verificar que estamos en la raiz de Laravel ---
if (-not (Test-Path ".\artisan")) {
    Write-Host "ERROR: no encuentro 'artisan'. Ejecuta este script desde la raiz de tu proyecto Laravel." -ForegroundColor Red
    exit 1
}

# --- 1. Crear archivos ---
Write-Host "1) Creando archivos del panel..." -ForegroundColor Yellow
$files = @{
    'README-ADMIN.md' = ''
    'app/Http/Controllers/Admin/AuthController.php' = ''
    'app/Http/Controllers/Admin/ClaimController.php' = ''
    'app/Http/Controllers/Admin/DashboardController.php' = ''
    'app/Http/Controllers/Admin/DocumentController.php' = ''
    'app/Http/Controllers/Admin/ExperienceController.php' = ''
    'app/Http/Controllers/Admin/VerificationRequestController.php' = ''
    'app/Http/Middleware/EnsureUserIsAdmin.php' = ''
    'app/Http/Middleware/HandleInertiaRequests.php' = ''
    'database/seeders/AdminUserSeeder.php' = ''
    'resources/css/app.css' = 'QGltcG9ydCAndGFpbHdpbmRjc3MnOwoKLyogRnVlbnRlIGRlbCBzaXN0ZW1hOyBhanVzdGEgc2kgdXNhcyBvdHJhLiAqLwpAdGhlbWUgewogICAgLS1mb250LXNhbnM6ICdJbnRlcicsIHVpLXNhbnMtc2VyaWYsIHN5c3RlbS11aSwgLWFwcGxlLXN5c3RlbSwgJ1NlZ29lIFVJJywgc2Fucy1zZXJpZjsKfQoKaHRtbCB7CiAgICBzY3JvbGwtYmVoYXZpb3I6IHNtb290aDsKfQo='
    'resources/js/Components/ConfirmModal.vue' = ''
    'resources/js/Components/Pagination.vue' = ''
    'resources/js/Components/StatusBadge.vue' = ''
    'resources/js/Layouts/AdminLayout.vue' = ''
    'resources/js/Pages/Affiliates/Index.vue' = ''
    'resources/js/Pages/Affiliates/Show.vue' = ''
    'resources/js/Pages/Auth/Login.vue' = ''
    'resources/js/Pages/Claims/Index.vue' = ''
    'resources/js/Pages/Claims/Show.vue' = ''
    'resources/js/Pages/Dashboard.vue' = ''
    'resources/js/Pages/Experiences/Index.vue' = ''
    'resources/js/Pages/Experiences/Show.vue' = ''
    'resources/js/app.ts' = ''
    'resources/js/lib/format.ts' = ''
    'resources/js/types/index.d.ts' = ''
    'resources/js/types/vue-shims.d.ts' = 'ZGVjbGFyZSBtb2R1bGUgJyoudnVlJyB7CiAgICBpbXBvcnQgdHlwZSB7IERlZmluZUNvbXBvbmVudCB9IGZyb20gJ3Z1ZSc7CiAgICBjb25zdCBjb21wb25lbnQ6IERlZmluZUNvbXBvbmVudDxSZWNvcmQ8c3RyaW5nLCB1bmtub3duPiwgUmVjb3JkPHN0cmluZywgdW5rbm93bj4sIHVua25vd24+OwogICAgZXhwb3J0IGRlZmF1bHQgY29tcG9uZW50Owp9Cg=='
    'resources/views/app.blade.php' = ''
    'tsconfig.json' = ''
    'vite.config.ts' = ''
}

$created = 0
foreach ($entry in $files.GetEnumerator()) {
    $path = $entry.Key -replace '/', '\'
    $dir  = Split-Path $path -Parent
    if ($dir -and -not (Test-Path $dir)) {
        New-Item -ItemType Directory -Path $dir -Force | Out-Null
    }
    $bytes = [System.Convert]::FromBase64String($entry.Value)
    $abs   = Join-Path (Get-Location).Path $path
    [System.IO.File]::WriteAllBytes($abs, $bytes)
    Write-Host "   + $path"
    $created++
}
Write-Host "   $created archivos creados." -ForegroundColor Green
Write-Host ""

# --- 2. Parchear bootstrap/app.php ---
Write-Host "2) Configurando bootstrap/app.php..." -ForegroundColor Yellow
$bootstrap = "bootstrap\app.php"
if (Test-Path $bootstrap) {
    $content = Get-Content $bootstrap -Raw
    if ($content -notmatch 'EnsureUserIsAdmin') {
        Copy-Item $bootstrap "$bootstrap.bak" -Force
        $inject = @'

        $middleware->web(append: [
            \App\Http\Middleware\HandleInertiaRequests::class,
        ]);
        $middleware->alias([
            'admin' => \App\Http\Middleware\EnsureUserIsAdmin::class,
        ]);
        $middleware->redirectGuestsTo(fn () => route('admin.login'));
'@
        $marker = '->withMiddleware(function (Middleware $middleware'
        $idx = $content.IndexOf($marker)
        if ($idx -ge 0) {
            $brace = $content.IndexOf('{', $idx)
            if ($brace -ge 0) {
                $content = $content.Substring(0, $brace + 1) + $inject + $content.Substring($brace + 1)
                [System.IO.File]::WriteAllText((Join-Path (Get-Location).Path $bootstrap), $content)
                Write-Host "   bootstrap/app.php parcheado (backup: bootstrap/app.php.bak)" -ForegroundColor Green
            }
        } else {
            Write-Host "   No pude ubicar withMiddleware(). Agrega manualmente (ver README-ADMIN.md, paso 4)." -ForegroundColor Magenta
        }
    } else {
        Write-Host "   Ya estaba configurado, no toco nada." -ForegroundColor Green
    }
} else {
    Write-Host "   No existe bootstrap/app.php (estructura distinta). Revisa el README." -ForegroundColor Magenta
}
Write-Host ""

# --- 3. Agregar rutas a routes/web.php ---
Write-Host "3) Agregando rutas a routes/web.php..." -ForegroundColor Yellow
$webRoutes = "routes\web.php"
$routeBlock = @'
// === AndanDO Admin Panel (agregado por setup-andando-admin.ps1) ===
Route::prefix('admin')->name('admin.')->group(function () {
    Route::middleware('guest')->group(function () {
        Route::get('login', [\App\Http\Controllers\Admin\AuthController::class, 'create'])->name('login');
        Route::post('login', [\App\Http\Controllers\Admin\AuthController::class, 'store'])->name('login.store');
    });
    Route::middleware(['auth', 'admin'])->group(function () {
        Route::post('logout', [\App\Http\Controllers\Admin\AuthController::class, 'destroy'])->name('logout');
        Route::get('/', [\App\Http\Controllers\Admin\DashboardController::class, 'index'])->name('dashboard');

        Route::get('afiliados', [\App\Http\Controllers\Admin\VerificationRequestController::class, 'index'])->name('affiliates.index');
        Route::get('afiliados/{verificationRequest}', [\App\Http\Controllers\Admin\VerificationRequestController::class, 'show'])->name('affiliates.show');
        Route::post('afiliados/{verificationRequest}/aprobar', [\App\Http\Controllers\Admin\VerificationRequestController::class, 'approve'])->name('affiliates.approve');
        Route::post('afiliados/{verificationRequest}/rechazar', [\App\Http\Controllers\Admin\VerificationRequestController::class, 'reject'])->name('affiliates.reject');

        Route::get('documentos/{document}', [\App\Http\Controllers\Admin\DocumentController::class, 'show'])->name('documents.show');

        Route::get('reclamos', [\App\Http\Controllers\Admin\ClaimController::class, 'index'])->name('claims.index');
        Route::get('reclamos/{claim}', [\App\Http\Controllers\Admin\ClaimController::class, 'show'])->name('claims.show');
        Route::post('reclamos/{claim}/resolver', [\App\Http\Controllers\Admin\ClaimController::class, 'resolve'])->name('claims.resolve');
        Route::post('reclamos/{claim}/rechazar', [\App\Http\Controllers\Admin\ClaimController::class, 'reject'])->name('claims.reject');

        Route::get('experiencias', [\App\Http\Controllers\Admin\ExperienceController::class, 'index'])->name('experiences.index');
        Route::get('experiencias/{experience}', [\App\Http\Controllers\Admin\ExperienceController::class, 'show'])->name('experiences.show');
        Route::post('experiencias/{experience}/estado', [\App\Http\Controllers\Admin\ExperienceController::class, 'toggleActive'])->name('experiences.toggle');
        Route::post('experiencias/{experience}/rechazar', [\App\Http\Controllers\Admin\ExperienceController::class, 'reject'])->name('experiences.reject');
    });
});
'@
if (Test-Path $webRoutes) {
    $rc = Get-Content $webRoutes -Raw
    if ($rc -notmatch 'AndanDO Admin Panel') {
        Copy-Item $webRoutes "$webRoutes.bak" -Force
        Add-Content $webRoutes "`n$routeBlock"
        Write-Host "   Rutas agregadas (backup: routes/web.php.bak)" -ForegroundColor Green
    } else {
        Write-Host "   Las rutas ya estaban presentes." -ForegroundColor Green
    }
} else {
    Write-Host "   No existe routes/web.php." -ForegroundColor Magenta
}
Write-Host ""

# --- 4. Dependencias ---
Write-Host "4) Instalando dependencias (puede tardar)..." -ForegroundColor Yellow
$ErrorActionPreference = "Continue"

Write-Host "   composer require inertiajs/inertia-laravel"
composer require inertiajs/inertia-laravel
if ($LASTEXITCODE -ne 0) { Write-Host "   AVISO: composer fallo. Correlo manual." -ForegroundColor Magenta }

Write-Host "   npm install @inertiajs/vue3 vue"
npm install @inertiajs/vue3 vue
if ($LASTEXITCODE -ne 0) { Write-Host "   AVISO: npm install fallo." -ForegroundColor Magenta }

Write-Host "   npm install -D @vitejs/plugin-vue @tailwindcss/vite typescript vue-tsc @types/node"
npm install -D "@vitejs/plugin-vue" "@tailwindcss/vite" typescript vue-tsc "@types/node"
if ($LASTEXITCODE -ne 0) { Write-Host "   AVISO: npm install -D fallo." -ForegroundColor Magenta }

$ErrorActionPreference = "Stop"
Write-Host ""

# --- 5. Final ---
Write-Host "== Casi listo ==" -ForegroundColor Cyan
Write-Host ""
Write-Host "Faltan 2 pasos manuales:" -ForegroundColor Yellow
Write-Host "  a) Edita database/seeders/AdminUserSeeder.php (correos y claves de tus 3 admins) y corre:"
Write-Host "        php artisan db:seed --class=AdminUserSeeder"
Write-Host "  b) Compila el front:"
Write-Host "        npm run dev    (desarrollo)   o   npm run build   (produccion)"
Write-Host ""
Write-Host "Luego entra a:  http://TU-APP/admin/login" -ForegroundColor Green
Write-Host ""
